import argparse
import os
import subprocess
import sys
from pathlib import Path


def run(cmd, cwd=None):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)


def main():
    parser = argparse.ArgumentParser(description="CI/CD deployment automation script")
    parser.add_argument("--requirements", default="requirements.txt", help="Path to requirements.txt")
    parser.add_argument("--test-cmd", default="pytest -q", help="Test command to run")
    parser.add_argument("--package-dir", default="dist", help="Directory to place deployment package")
    parser.add_argument("--skip-tests", action="store_true", help="Skip tests")
    args = parser.parse_args()

    project_root = Path.cwd()
    requirements = project_root / args.requirements
    package_dir = project_root / args.package_dir

    if requirements.exists():
        run([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
        run([sys.executable, "-m", "pip", "install", "-r", str(requirements)])
    else:
        print(f"Requirements file not found: {requirements}", flush=True)

    if not args.skip_tests:
        run(args.test_cmd, cwd=project_root, ) if isinstance(args.test_cmd, list) else run(args.test_cmd.split(), cwd=project_root)

    package_dir.mkdir(parents=True, exist_ok=True)

    tar_name = package_dir / "deployment_package.tar.gz"
    run(["tar", "-czf", str(tar_name), "--exclude", str(package_dir), "."])

    print(f"Deployment package created at: {tar_name}", flush=True)


if __name__ == "__main__":
    main()